package main

import (
	"fmt"
	"os/exec"
	"regexp"
	"strconv"
)

// MeasureLatency pings a specified host a user-defined number of times
// and returns the average latency in milliseconds.
func MeasureLatency(host string, count int) (float64, error) {
	if count <= 0 {
		return 0, fmt.Errorf("count must be positive, got %d", count)
	}

	if host == "" {
		return 0, fmt.Errorf("host cannot be empty")
	}

	// Execute ping command with count parameter
	// -c specifies the number of ping attempts (Unix-like systems)
	cmd := exec.Command("ping", "-c", strconv.Itoa(count), host)
	output, err := cmd.Output()
	if err != nil {
		if exitErr, ok := err.(*exec.ExitError); ok {
			return 0, fmt.Errorf("ping command failed: %s", string(exitErr.Stderr))
		}
		return 0, fmt.Errorf("ping command failed: %w", err)
	}

	// Parse the output to extract latency values
	// Common patterns: "time=0.123 ms", "time=0.123ms", "time<0.123 ms"
	re := regexp.MustCompile(`time[=<](\d+\.?\d*)\s*ms`)
	matches := re.FindAllStringSubmatch(string(output), -1)

	if len(matches) == 0 {
		return 0, fmt.Errorf("no latency values found in ping output")
	}

	var total float64
	validCount := 0
	for _, match := range matches {
		if len(match) < 2 {
			continue
		}
		latency, err := strconv.ParseFloat(match[1], 64)
		if err != nil {
			continue
		}
		total += latency
		validCount++
	}

	if validCount == 0 {
		return 0, fmt.Errorf("no valid latency values parsed")
	}

	avgLatency := total / float64(validCount)
	return avgLatency, nil
}

