		cmd = exec.Command("ping", "-n", strconv.Itoa(count), host)
	} else {
		// Unix-like systems use -c for count
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
	}

	// Execute the command. CombinedOutput captures both stdout and stderr.
	output, err := cmd.CombinedOutput()

	// If the command failed to start (e.g., ping not found), output will be nil
	if output == nil {
		return 0, err
	}

	// Regex to match individual ping times
	// Matches: time=0.123 ms (Linux/macOS), time=0.123ms (Windows), time<1ms
	re := regexp.MustCompile(`time[=<](\d+\.?\d*)\s*ms`)
	matches := re.FindAllStringSubmatch(string(output), -1)

	if len(matches) == 0 {
