		if m := linRe.FindStringSubmatch(string(output)); len(m) > 1 {
			val, err := strconv.ParseFloat(m[1], 64)
			return val, err
		}
		if m := macRe.FindStringSubmatch(string(output)); len(m) > 1 {
			val, err := strconv.ParseFloat(m[1], 64)
			return val, err
