package main

import (
	"fmt"
	"os/exec"
	"regexp"
	"runtime"
	"strconv"
	"strings"
)

// MeasureLatency pings a specified host a user-defined number of times
// and returns the average latency in milliseconds.
func MeasureLatency(host string, count int) (float64, error) {
	if count <= 0 {
		return 0, fmt.Errorf("count must be positive")
	}
	if host == "" {
		return 0, fmt.Errorf("host cannot be empty")
	}

	var cmd *exec.Cmd

	// Different ping command syntax for different OS
	if runtime.GOOS == "windows" {
		cmd = exec.Command("ping", "-n", fmt.Sprintf("%d", count), host)
	} else {
		cmd = exec.Command("ping", "-c", fmt.Sprintf("%d", count), host)
	}

	output, err := cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("ping command failed: %v", err)
	}

	// Parse the output to get average latency
	avgLatency, err := parsePingOutput(string(output))
	if err != nil {
		return 0, err
	}

	return avgLatency, nil
}

func parsePingOutput(output string) (float64, error) {
	lines := strings.Split(output, "\n")

	// Try multiple regex patterns for different ping output formats
	patterns := []string{
		// Linux/macOS: rtt min/avg/max/mdev = 10.123/15.456/20.789/0.123 ms
		`rtt min/avg/max/mdev\s*=\s*\d+\.?\d*/(\d+\.?\d*)/`,
		// Alternative Linux format: round-trip min/avg/max/stddev = 10.123/15.456/20.789/0.123 ms
		`round-trip min/avg/max/stddev\s*=\s*\d+\.?\d*/(\d+\.?\d*)/`,
		// Windows: Average = 15ms or Average = 15.123ms
		`Average\s*=\s*(\d+\.?\d*)\s*ms`,
		// Alternative Windows format
		`Average\s*=\s*(\d+\.?\d*)`,
	}

	for _, pattern := range patterns {
		re := regexp.MustCompile(pattern)
		for _, line := range lines {
			matches := re.FindStringSubmatch(line)
			if len(matches) >= 2 {
				latency, err := strconv.ParseFloat(matches[1], 64)
				if err != nil {
					continue
				}
				return latency, nil
			}
		}
	}

	return 0, fmt.Errorf("could not parse average latency from ping output")
}

func main() {
	host := "google.com"
	count := 4

	latency, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Printf("Error measuring latency: %v\n", err)
		return
	}

	fmt.Printf("Average latency to %s: %.2f ms\n", host, latency)
}

