package main

import (
	"fmt"
	"os"
	"os/exec"
	"regexp"
	"strconv"
	"strings"
)

// MeasureLatency pings a specified host a user-defined number of times
// and returns the average latency in milliseconds.
func MeasureLatency(host string, count int) (float64, error) {
	if count <= 0 {
		return 0, fmt.Errorf("count must be positive, got %d", count)
	}

	if host == "" {
		return 0, fmt.Errorf("host cannot be empty")
	}

	// Determine the ping command based on OS
	var cmd *exec.Cmd
	if isWindows() {
		// Windows ping command: ping -n <count> <host>
		cmd = exec.Command("ping", "-n", fmt.Sprintf("%d", count), host)
	} else {
		// Unix/Linux/Mac ping command: ping -c <count> <host>
		cmd = exec.Command("ping", "-c", fmt.Sprintf("%d", count), host)
	}

	output, err := cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("ping command failed: %w", err)
	}

	// Parse the output to extract latency values
	latencies, err := parsePingOutput(string(output))
	if err != nil {
		return 0, fmt.Errorf("failed to parse ping output: %w", err)
	}

	if len(latencies) == 0 {
		return 0, fmt.Errorf("no latency values found in ping output")
	}

	// Calculate average latency
	var sum float64
	for _, latency := range latencies {
		sum += latency
	}

	average := sum / float64(len(latencies))
	return average, nil
}

// isWindows checks if the current OS is Windows
func isWindows() bool {
	return strings.Contains(strings.ToLower(os.Getenv("OS")), "windows") ||
		strings.Contains(strings.ToLower(os.Getenv("GOOS")), "windows")
}

// parsePingOutput extracts latency values from ping command output
func parsePingOutput(output string) ([]float64, error) {
	var latencies []float64

	// Pattern for Unix/Linux/Mac: time=0.123 ms or time=0.123ms
	// Pattern for Windows: time=<1ms or time=1ms
	latencyPattern := regexp.MustCompile(`time[=<](\d+\.?\d*)\s*ms`)

	matches := latencyPattern.FindAllStringSubmatch(output, -1)
	for _, match := range matches {
		if len(match) >= 2 {
			latency, err := strconv.ParseFloat(match[1], 64)
			if err != nil {
				continue
			}
			latencies = append(latencies, latency)
		}
	}

	return latencies, nil
}

func main() {
	// Default values
	host := "google.com"
	count := 4

	// Allow command line arguments to override defaults
	if len(os.Args) >= 2 {
		host = os.Args[1]
	}
	if len(os.Args) >= 3 {
		var err error
		count, err = strconv.Atoi(os.Args[2])
		if err != nil {
			fmt.Fprintf(os.Stderr, "Error: count must be a valid integer\n")
			os.Exit(1)
		}
	}

	avgLatency, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Fprintf(os.Stderr, "Error measuring latency: %v\n", err)
		os.Exit(1)
	}

	fmt.Printf("Average latency to %s: %.2f ms\n", host, avgLatency)
}

