package main

import (
	"fmt"
	"os/exec"
	"regexp"
	"runtime"
	"strconv"
)

// MeasureLatency pings a specified host a user-defined number of times
// and returns the average latency in milliseconds.
func MeasureLatency(host string, count int) (float64, error) {
	if count <= 0 {
		return 0, fmt.Errorf("count must be greater than 0")
	}

	var cmd *exec.Cmd
	// Handle OS-specific ping flags
	if runtime.GOOS == "windows" {
		cmd = exec.Command("ping", "-n", strconv.Itoa(count), host)
	} else {
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
	}

	output, err := cmd.CombinedOutput()
	// ping returns non-zero exit code if packets are lost, but output still contains stats
	if err != nil {
		if _, ok := err.(*exec.ExitError); !ok {
			// If error is not ExitError (e.g., command not found), return it
			return 0, err
		}
	}

	// Regex to extract latency values (e.g., time=0.123 ms or time=1ms)
	// This pattern matches 'time=' followed by digits and optional decimals
	re := regexp.MustCompile(`time=([0-9.]+)`)
	matches := re.FindAllStringSubmatch(string(output), -1)

	if len(matches) == 0 {
		return 0, fmt.Errorf("no latency values found in ping output")
	}

	var totalLatency float64
	validCount := 0

	for _, match := range matches {
		val, err := strconv.ParseFloat(match[1], 64)
		if err == nil {
			totalLatency += val
			validCount++
		}
	}

	if validCount == 0 {
		return 0, fmt.Errorf("failed to parse any valid latency values")
	}

	return totalLatency / float64(validCount), nil
}

func main() {
	host := "google.com"
	count := 4

	fmt.Printf("Measuring latency to %s (%d pings)...\n", host, count)
	avg, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Printf("Error measuring latency: %v\n", err)
		return
	}

	fmt.Printf("Average latency: %.2f ms\n", avg)
}

