package main

import (
	"fmt"
	"os/exec"
	"regexp"
	"runtime"
	"strconv"
	"strings"
)

// MeasureLatency pings a specified host a user-defined number of times
// and returns the average latency in milliseconds.
func MeasureLatency(host string, count int) (float64, error) {
	if count <= 0 {
		return 0, fmt.Errorf("count must be positive, got %d", count)
	}

	if strings.TrimSpace(host) == "" {
		return 0, fmt.Errorf("host cannot be empty")
	}

	var cmd *exec.Cmd

	// Different ping command syntax for different OS
	if runtime.GOOS == "windows" {
		cmd = exec.Command("ping", "-n", fmt.Sprintf("%d", count), host)
	} else {
		// Linux, macOS, and other Unix-like systems
		cmd = exec.Command("ping", "-c", fmt.Sprintf("%d", count), host)
	}

	output, err := cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("ping command failed: %w, output: %s", err, string(output))
	}

	return parsePingOutput(string(output))
}

// parsePingOutput extracts latency values from ping command output
// and calculates the average latency in milliseconds.
func parsePingOutput(output string) (float64, error) {
	var latencies []float64

	// Pattern to match time values in ping output
	// Common formats:
	// Linux/macOS: time=0.123 ms
	// Windows: time<1ms or time=0.123ms
	timeRegex := regexp.MustCompile(`time[=<](\d+\.?\d*)\s*ms`)
	matches := timeRegex.FindAllStringSubmatch(output, -1)

	for _, match := range matches {
		if len(match) > 1 {
			latency, err := strconv.ParseFloat(match[1], 64)
			if err == nil {
				latencies = append(latencies, latency)
			}
		}
	}

	if len(latencies) == 0 {
		return 0, fmt.Errorf("no latency values found in ping output")
	}

	// Calculate average latency
	var sum float64
	for _, latency := range latencies {
		sum += latency
	}

	return sum / float64(len(latencies)), nil
}

func main() {
	// Default values for demonstration
	host := "google.com"
	count := 4

	// Allow command-line arguments to override defaults
	if len(os.Args) > 1 {
		host = os.Args[1]
	}
	if len(os.Args) > 2 {
		var err error
		count, err = strconv.Atoi(os.Args[2])
		if err != nil {
			fmt.Printf("Error: invalid count value: %v\n", err)
			return
		}
	}

	fmt.Printf("Measuring latency to %s (%d pings)...\n", host, count)

	avgLatency, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Printf("Error measuring latency: %v\n", err)
		return
	}

	fmt.Printf("Average latency to %s: %.2f ms\n", host, avgLatency)
}

