package main

import (
	"bufio"
	"fmt"
	"os/exec"
	"regexp"
	"strconv"
	"strings"
)

// MeasureLatency pings a specified host a user-defined number of times
// and returns the average latency in milliseconds.
func MeasureLatency(host string, count int) (float64, error) {
	if count <= 0 {
		return 0, fmt.Errorf("count must be positive, got %d", count)
	}

	if host == "" {
		return 0, fmt.Errorf("host cannot be empty")
	}

	// Execute ping command with count parameter
	// Using -c flag for Unix/Linux/Mac systems
	cmd := exec.Command("ping", "-c", strconv.Itoa(count), host)

	output, err := cmd.Output()
	if err != nil {
		if exitErr, ok := err.(*exec.ExitError); ok {
			return 0, fmt.Errorf("ping command failed with exit code %d: %w", exitErr.ExitCode(), err)
		}
		return 0, fmt.Errorf("ping command failed: %w", err)
	}

	// Parse the output to extract latency values
	// Ping output typically contains lines like:
	// 64 bytes from 8.8.8.8: icmp_seq=1 ttl=117 time=15.3 ms
	timeRegex := regexp.MustCompile(`time=([0-9.]+)\s*ms`)

	scanner := bufio.NewScanner(strings.NewReader(string(output)))

	var totalLatency float64
	var latencyCount int

	for scanner.Scan() {
		line := scanner.Text()
		matches := timeRegex.FindStringSubmatch(line)
		if len(matches) >= 2 {
			latency, err := strconv.ParseFloat(matches[1], 64)
			if err != nil {
				continue
			}
			totalLatency += latency
			latencyCount++
		}
	}

	if err := scanner.Err(); err != nil {
		return 0, fmt.Errorf("error reading ping output: %w", err)
	}

	if latencyCount == 0 {
		return 0, fmt.Errorf("no latency measurements found in ping output")
	}

	averageLatency := totalLatency / float64(latencyCount)
	return averageLatency, nil
}

func main() {
	// Default configuration
	host := "8.8.8.8"
	count := 4

	// Measure latency
	latency, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Printf("Error measuring latency: %v\n", err)
		return
	}

	fmt.Printf("Average latency to %s: %.2f ms (based on %d successful pings)\n", host, latency, count)
}

