package main

import (
	"fmt"
	"os"
	"os/exec"
	"regexp"
	"runtime"
	"strconv"
)

// MeasureLatency pings a specified host a user-defined number of times
// and returns the average latency in milliseconds.
func MeasureLatency(host string, count int) (float64, error) {
	if count <= 0 {
		return 0, fmt.Errorf("count must be greater than 0")
	}

	var cmd *exec.Cmd
	// Handle differences between Windows and Unix-like systems for the ping command
	if runtime.GOOS == "windows" {
		cmd = exec.Command("ping", "-n", strconv.Itoa(count), host)
	} else {
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
	}

	// Execute the command and capture combined output (stdout and stderr)
	out, err := cmd.CombinedOutput()
	if err != nil && len(out) == 0 {
		// If there is no output, the command likely failed to start (e.g., ping not found)
		return 0, fmt.Errorf("failed to execute ping command: %w", err)
	}

	output := string(out)

	// Regex to extract latency values.
	// Matches patterns like "time=0.123 ms" (Linux/macOS) or "time=10ms" (Windows)
	// Captures the numeric value before 'ms'
	re := regexp.MustCompile(`time[=<](\d+\.?\d*)\s*ms`)
	matches := re.FindAllStringSubmatch(output, -1)

	if len(matches) == 0 {
		return 0, fmt.Errorf("failed to parse latency from ping output (permission denied or host unreachable?)")
	}

	var totalLatency float64
	validCount := 0

	for _, match := range matches {
		if len(match) > 1 {
			val, err := strconv.ParseFloat(match[1], 64)
			if err == nil {
				totalLatency += val
				validCount++
			}
		}
	}

	if validCount == 0 {
		return 0, fmt.Errorf("no valid latency values parsed")
	}

	return totalLatency / float64(validCount), nil
}

func main() {
	host := "google.com"
	count := 4

	if len(os.Args) > 1 {
		host = os.Args[1]
	}
	if len(os.Args) > 2 {
		c, err := strconv.Atoi(os.Args[2])
		if err == nil && c > 0 {
			count = c
		}
	}

	avgLatency, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Fprintf(os.Stderr, "Error measuring latency: %v\n", err)
		os.Exit(1)
	}

	fmt.Printf("Average latency to %s over %d pings: %.2f ms\n", host, count, avgLatency)
}

