// MeasureLatency pings a specified host a user-defined number of times
// and returns the average latency in milliseconds.
func MeasureLatency(host string, count int) (float64, error) {
	if count <= 0 {
		return 0, fmt.Errorf("count must be positive, got %d", count)
	}

	if host == "" {
		return 0, fmt.Errorf("host cannot be empty")
	}

	var cmd *exec.Cmd

	// Different ping command syntax for different OS
	if runtime.GOOS == "windows" {
		cmd = exec.Command("ping", "-n", fmt.Sprintf("%d", count), host)
	} else {
		// Linux/Mac/Unix
		cmd = exec.Command("ping", "-c", fmt.Sprintf("%d", count), host)
	}

	output, err := cmd.Output()
	if err != nil {
		if exitErr, ok := err.(*exec.ExitError); ok {
			return 0, fmt.Errorf("ping command failed: %s", string(exitErr.Stderr))
		}
		return 0, fmt.Errorf("ping command failed: %w", err)
	}

	return parsePingOutput(string(output), runtime.GOOS)
}

func parsePingOutput(output string, os string) (float64, error) {
	var latencies []float64
	scanner := bufio.NewScanner(strings.NewReader(output))

	// Regex patterns for different OS to extract latency values
	var timeRegex *regexp.Regexp
	if os == "windows" {
		// Windows: time<1ms or time=10ms or time=10.5ms
		timeRegex = regexp.MustCompile(`(?i)time[=<](\d+\.?\d*)ms`)
	} else {
		// Linux/Mac: time=0.123 ms or time=10.5 ms
		timeRegex = regexp.MustCompile(`time[=<](\d+\.?\d*)\s*ms`)
	}

	for scanner.Scan() {
		line := scanner.Text()
		matches := timeRegex.FindStringSubmatch(line)
		if len(matches) >= 2 {
			latency, err := strconv.ParseFloat(matches[1], 64)
			if err != nil {
				continue
			}
			latencies = append(latencies, latency)
		}
	}

	if len(latencies) == 0 {
		return 0, fmt.Errorf("no latency values found in ping output")
	}

	// Calculate average latency
	var sum float64
	for _, lat := range latencies {
		sum += lat
	}

	average := sum / float64(len(latencies))
	return average, nil
}

func main() {
	host := "google.com"
	count := 4

