package main

import (
	"errors"
	"fmt"
	"net"
	"os/exec"
	"regexp"
	"strconv"
	"strings"
)

// MeasureLatency pings the specified host the given number of times and returns the average latency in milliseconds.
// It uses the system 'ping' command via os/exec and parses the output to extract the average RTT.
func MeasureLatency(host string, count int) (float64, error) {
	if host == "" {
		return 0, errors.New("host cannot be empty")
	}
	if count <= 0 {
		return 0, errors.New("count must be positive")
	}

	// Validate host format to prevent command injection
	if !isValidHost(host) {
		return 0, errors.New("invalid host format")
	}

	// Limit count to reasonable bounds to prevent resource exhaustion
	if count > 100 {
		return 0, errors.New("count must not exceed 100")
	}

	// SECURITY FIX: Use exec.Command directly with arguments instead of bash -c
	// This prevents command injection by not invoking a shell interpreter
	// Arguments are passed as separate parameters, not concatenated into a shell command string
	cmd := exec.Command("ping", "-c", strconv.Itoa(count), host)
	output, err := cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("failed to execute ping: %w (output: %s)", err, string(output))
	}

	// Look for the line containing RTT statistics
	outputStr := string(output)
	lines := strings.Split(outputStr, "\n")
	var statsLine string
	for _, line := range lines {
		if strings.Contains(line, "rtt min/avg/max") {
			statsLine = line
			break
		}
	}

	if statsLine == "" {
		return 0, errors.New("could not find RTT statistics in ping output")
	}

	// Extract average latency using regex
	// Example line: rtt min/avg/max/mdev = 12.345/23.456/34.567/5.678 ms
	re := regexp.MustCompile(`rtt min/avg/max/mdev = \d+\.\d+/([\d.]+)/\d+\.\d+/\d+\.\d+ ms`)
	matches := re.FindStringSubmatch(statsLine)
	if len(matches) < 2 {
		return 0, errors.New("failed to parse average latency from ping output")
	}

	avgStr := matches[1]
	avg, err := strconv.ParseFloat(avgStr, 64)
	if err != nil {
		return 0, fmt.Errorf("failed to convert average latency to float: %w", err)
	}

	return avg, nil
}

// isValidHost validates that the host string is a valid hostname or IP address
// and does not contain characters that could be used for command injection
func isValidHost(host string) bool {
	// Check for dangerous characters that could be used for command injection
	dangerousChars := []string{
		";", "|", "&", "$", "`", "(", ")", "{", "}", "[", "]",
		"<", ">", "\\", "\n", "\r", " ", "'", "\"", "*", "?", "!",
	}
	for _, char := range dangerousChars {
		if strings.Contains(host, char) {
			return false
		}
	}

	// Try to parse as IP address
	if net.ParseIP(host) != nil {
		return true
	}

	// Validate as hostname using regex
	// Hostname can contain letters, numbers, hyphens, and dots
	// Must start and end with alphanumeric character
	hostRegex := regexp.MustCompile(`^[a-zA-Z0-9]([a-zA-Z0-9\-\.]*[a-zA-Z0-9])?$`)
	if !hostRegex.MatchString(host) {
		return false
	}

	// Additional check: ensure no consecutive dots or hyphens at boundaries
	if strings.Contains(host, "..") {
		return false
	}

	return true
}

