package main

import (
	"fmt"
	"os/exec"
	"regexp"
	"runtime"
	"strconv"
)

// MeasureLatency pings a specified host a user-defined number of times
// and returns the average latency in milliseconds.
func MeasureLatency(host string, count int) (float64, error) {
	if host == "" {
		return 0, fmt.Errorf("host cannot be empty")
	}
	if count <= 0 {
		return 0, fmt.Errorf("count must be greater than 0")
	}

	var cmd *exec.Cmd
	// Handle different ping command flags for Windows vs Unix-like systems
	if runtime.GOOS == "windows" {
		cmd = exec.Command("ping", "-n", strconv.Itoa(count), host)
	} else {
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
	}

	output, err := cmd.CombinedOutput()
	// Note: ping may return a non-zero exit code if packets are lost,
	// but we still attempt to parse the output for successful replies.
	// If the command itself fails to start (e.g., ping not found), output might be empty.
	if err != nil && len(output) == 0 {
		return 0, err
	}

	// Regex to extract latency values.
	// Matches "time=12.3" (Linux/macOS) or "time=12" (Windows)
	// Captures the numeric part.
	re := regexp.MustCompile(`time=([0-9.]+)`)
	matches := re.FindAllStringSubmatch(string(output), -1)

	if len(matches) == 0 {
		return 0, fmt.Errorf("failed to parse latency from ping output or host unreachable")
	}

	var totalLatency float64
	validMeasurements := 0

	for _, match := range matches {
		if len(match) > 1 {
			latency, err := strconv.ParseFloat(match[1], 64)
			if err == nil {
				totalLatency += latency
				validMeasurements++
			}
		}
	}

	if validMeasurements == 0 {
		return 0, fmt.Errorf("no valid latency measurements found")
	}

	averageLatency := totalLatency / float64(validMeasurements)
	return averageLatency, nil
}

func main() {
	host := "google.com"
	count := 3

	latency, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Printf("Error measuring latency: %v\n", err)
		return
	}

	fmt.Printf("Average latency to %s over %d pings: %.2f ms\n", host, count, latency)
}

