package main

import (
	"fmt"
	"os/exec"
	"regexp"
	"runtime"
	"strconv"
)

// MeasureLatency pings a specified host a user-defined number of times
// and returns the average latency in milliseconds.
func MeasureLatency(host string, count int) (float64, error) {
	if count <= 0 {
		return 0, fmt.Errorf("count must be greater than 0")
	}

	var cmd *exec.Cmd
	// Determine ping command arguments based on OS
	// Windows uses -n, Unix-like systems use -c
	if runtime.GOOS == "windows" {
		cmd = exec.Command("ping", "-n", strconv.Itoa(count), host)
	} else {
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
	}

	// Execute the command
	out, err := cmd.Output()
	if err != nil {
		return 0, fmt.Errorf("failed to execute ping command: %w", err)
	}

	// Regular expression to extract latency values (e.g., time=0.123 ms or time=1ms)
	// This pattern looks for 'time=' followed by numbers (including decimals)
	re := regexp.MustCompile(`time=([0-9.]+)`)
	matches := re.FindAllStringSubmatch(string(out), -1)

	if len(matches) == 0 {
		return 0, fmt.Errorf("no latency values found in ping output")
	}

	var totalLatency float64
	var validMeasurements int

	for _, match := range matches {
		if len(match) < 2 {
			continue
		}
		latency, err := strconv.ParseFloat(match[1], 64)
		if err != nil {
			continue
		}
		totalLatency += latency
		validMeasurements++
	}

	if validMeasurements == 0 {
		return 0, fmt.Errorf("failed to parse any valid latency values")
	}

	return totalLatency / float64(validMeasurements), nil
}

func main() {
	host := "google.com"
	count := 3

	fmt.Printf("Measuring latency to %s (%d pings)...\n", host, count)
	avgLatency, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Printf("Error measuring latency: %v\n", err)
		return
	}

	fmt.Printf("Average latency: %.2f ms\n", avgLatency)
}

