	}

	output, err := cmd.CombinedOutput()
	if err != nil {
		// Ping might return non-zero exit code if packets are lost, 
		// but we still might have output to parse. 
		// However, if command fails to start, output might be empty.
		if len(output) == 0 {
			return 0, fmt.Errorf("failed to execute ping command: %w", err)
		}
	}

	// Regex to match latency time. 
	// Matches patterns like: time=0.034 ms, time=1ms, time=<1ms
	// Captures the numeric part.
	re := regexp.MustCompile(`time=<?([0-9.]+)\s*ms`)
	matches := re.FindAllStringSubmatch(string(output), -1)

	if len(matches) == 0 {
		return 0, fmt.Errorf("no latency measurements found in ping output")
	}

	var totalLatency float64
	validMatches := 0
	for _, match := range matches {
		if len(match) < 2 {
			continue
		}
		val, err := strconv.ParseFloat(match[1], 64)
		if err != nil {
			continue
		}
		totalLatency += val
		validMatches++
	}

	if validMatches == 0 {
		return 0, fmt.Errorf("failed to parse latency values")
	}

	averageLatency := totalLatency / float64(validMatches)
	return averageLatency, nil
}

func main() {
	host := "google.com"
	count := 4

	if len(os.Args) > 1 {
		host = os.Args[1]
	}
	if len(os.Args) > 2 {
		var err error
		count, err = strconv.Atoi(os.Args[2])
		if err != nil {
			fmt.Fprintf(os.Stderr, "Invalid count: %v\n", err)
			os.Exit(1)
