package main

import (
	"errors"
	"fmt"
	"os/exec"
	"regexp"
	"runtime"
	"strconv"
)

// MeasureLatency pings a specified host a user-defined number of times
// and returns the average latency in milliseconds.
func MeasureLatency(host string, count int) (float64, error) {
	if count <= 0 {
		return 0, errors.New("count must be a positive integer")
	}

	// Determine ping command arguments based on OS
	var args []string
	if runtime.GOOS == "windows" {
		// Windows uses -n for count
		args = []string{"-n", strconv.Itoa(count), host}
	} else {
		// Unix-like systems (Linux, macOS) use -c for count
		args = []string{"-c", strconv.Itoa(count), host}
	}

	// Execute the ping command
	cmd := exec.Command("ping", args...)
	output, err := cmd.Output()
	if err != nil {
		// If ping fails (e.g., unknown host, network unreachable), return error
		// exec.ExitError contains stderr output which might be useful for debugging
		return 0, fmt.Errorf("ping command execution failed: %w", err)
	}

	// Regex to extract latency values.
	// Matches patterns like "time=0.123 ms" (Linux/macOS) or "time=10ms" (Windows)
	// Group 1 captures the numeric value.
	re := regexp.MustCompile(`time[=<](\d+\.?\d*)\s*ms`)
	matches := re.FindAllStringSubmatch(string(output), -1)

	if len(matches) == 0 {
		return 0, errors.New("no latency values found in ping output")
	}

	var totalLatency float64
	var validCount int

	for _, match := range matches {
		if len(match) < 2 {
			continue
		}
		val, err := strconv.ParseFloat(match[1], 64)
		if err != nil {
			continue
		}
		totalLatency += val
		validCount++
	}

	if validCount == 0 {
		return 0, errors.New("failed to parse any valid latency values")
	}

	return totalLatency / float64(validCount), nil
}

func main() {
	host := "google.com"
	count := 4

	fmt.Printf("Measuring latency to %s (%d pings)...\n", host, count)
	avgLatency, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Printf("Error: %v\n", err)
		return
	}

	fmt.Printf("Average latency: %.2f ms\n", avgLatency)
}

