package main

import (
	"errors"
	"fmt"
	"os"
	"os/exec"
	"regexp"
	"runtime"
	"strconv"
)

// MeasureLatency pings a specified host a user-defined number of times
// and returns the average latency in milliseconds.
func MeasureLatency(host string, count int) (float64, error) {
	if host == "" {
		return 0, errors.New("host cannot be empty")
	}
	if count <= 0 {
		return 0, errors.New("count must be positive")
	}

	var cmd *exec.Cmd
	// Ping command flags differ between Windows and Unix-like systems
	if runtime.GOOS == "windows" {
		cmd = exec.Command("ping", "-n", strconv.Itoa(count), host)
	} else {
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
	}

	// Use CombinedOutput to capture both stdout and stderr
	output, err := cmd.CombinedOutput()

	// If the command failed to start or produced no output, return the error
	// This handles cases like "command not found" or immediate permission errors
	if err != nil && len(output) == 0 {
		return 0, err
	}

	// Regex to extract latency values (e.g., time=0.5 ms, time=1ms, time<1ms)
	// Captures numeric value after time= or time<
	re := regexp.MustCompile(`time[=<](\d+(?:\.\d+)?)`)
	matches := re.FindAllStringSubmatch(string(output), -1)

	if len(matches) == 0 {
		return 0, fmt.Errorf("failed to parse latency from ping output (host unreachable or permission denied)")
	}

	var totalLatency float64
	for _, match := range matches {
		val, err := strconv.ParseFloat(match[1], 64)
		if err != nil {
			continue
		}
		totalLatency += val
	}

	if len(matches) == 0 {
		return 0, errors.New("no valid latency values found")
	}

	return totalLatency / float64(len(matches)), nil
}

func main() {
	host := "google.com"
	count := 4

	if len(os.Args) > 1 {
		host = os.Args[1]
	}
	if len(os.Args) > 2 {
		c, err := strconv.Atoi(os.Args[2])
		if err != nil {
			fmt.Fprintf(os.Stderr, "Invalid count argument: %v\n", err)
			os.Exit(1)
		}
		count = c
	}

	avg, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Fprintf(os.Stderr, "Error measuring latency: %v\n", err)
		os.Exit(1)
	}

	fmt.Printf("Average latency to %s over %d pings: %.2f ms\n", host, count, avg)
}

